List<Question> getQuestionsForLevel(int level) {
  // Level 13 has only 2 questions (121–122)
  final start = (level - 1) * 10;
  final end = (start + 10).clamp(0, allQuestions.length);
  return allQuestions.sublist(start, end);
}

